  `total_retweets` int(10) unsigned NOT NULL DEFAULT 0,
  `weekly_likes` int(10) unsigned NOT NULL DEFAULT 0,
  `click_count` int(10) unsigned NOT NULL DEFAULT 0,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `videos_dmm_content_id_unique` (`dmm_content_id`),
  KEY `videos_total_likes_index` (`total_likes`),
  KEY `videos_release_date_index` (`release_date`),
  KEY `videos_weekly_likes_index` (`weekly_likes`)
